// Scoped to .cc-pikes-peak-eop. Generated by microsites/_dversion-build.mjs.
(function () {
  // Use window.document explicitly here — declaring  const document
  // = …  later in this scope hoists the binding to the top of the
  // function as TDZ, so plain  document.querySelector  on this line
  // would throw "Cannot access 'document' before initialization".
  const ROOT = window.document.querySelector('.cc-pikes-peak-eop');
  if (!ROOT) return;

  // Re-bind document.* lookups to resolve against the partial root,
  // so IDs and class selectors can't collide with the host Drupal page.
  const document = new Proxy(window.document, {
    get(target, prop) {
      if (prop === 'getElementById') return (id) => ROOT.querySelector('#' + CSS.escape(id));
      if (prop === 'querySelector') return (sel) => ROOT.querySelector(sel);
      if (prop === 'querySelectorAll') return (sel) => ROOT.querySelectorAll(sel);
      const v = target[prop];
      return typeof v === 'function' ? v.bind(target) : v;
    },
  });

/* ====================================================================
       Accessibility enhancements (progressive — no JS, page still works)
       ==================================================================== */
    (function () {
      'use strict';

      /* --- Back-to-top button --- */
      var btn = document.querySelector('.back-to-top');
      var prefersReduce = window.matchMedia('(prefers-reduced-motion: reduce)').matches;
      function toggleBtn() {
        if (window.scrollY > 600) btn.classList.add('is-visible');
        else btn.classList.remove('is-visible');
      }
      window.addEventListener('scroll', toggleBtn, { passive: true });
      btn.addEventListener('click', function () {
        window.scrollTo({ top: 0, behavior: prefersReduce ? 'auto' : 'smooth' });
        // Move focus to skip-link target so keyboard users land at the top
        var main = document.getElementById('main-content');
        if (main) main.focus({ preventScroll: true });
      });

      /* --- Scroll-spy: mark current TOC item with aria-current --- */
      var tocLinks = document.querySelectorAll('.toc__list a[href^="#"]');
      if (!('IntersectionObserver' in window) || tocLinks.length === 0) return;

      var linkById = {};
      tocLinks.forEach(function (a) {
        var id = a.getAttribute('href').slice(1);
        linkById[id] = a;
      });

      var visible = new Set();
      function setCurrent() {
        // Pick the topmost visible section
        var topId = null, topY = Infinity;
        visible.forEach(function (id) {
          var el = document.getElementById(id);
          if (!el) return;
          var y = el.getBoundingClientRect().top;
          if (y < topY) { topY = y; topId = id; }
        });
        tocLinks.forEach(function (a) { a.removeAttribute('aria-current'); });
        if (topId && linkById[topId]) {
          linkById[topId].setAttribute('aria-current', 'location');
        }
      }

      var observer = new IntersectionObserver(function (entries) {
        entries.forEach(function (e) {
          var id = e.target.id;
          if (e.isIntersecting) visible.add(id);
          else visible.delete(id);
        });
        setCurrent();
      }, { rootMargin: '-80px 0px -60% 0px', threshold: 0 });

      Object.keys(linkById).forEach(function (id) {
        var section = document.getElementById(id);
        if (section) observer.observe(section);
      });
    })();

  // (No inline on* handlers detected — nothing to expose on window.)
})();
